import sys
from collections import deque

class Solution:
    def solve(self, tree: list[int]) -> int:
        if not tree:
            return 0
        queue = deque([(0, 0)])
        max_height = 0
        while queue:
            node, height = queue.popleft()
            max_height = max(max_height, height)
            if node * 2 + 1 < len(tree) and tree[node * 2 + 1] != -1:
                queue.append((node * 2 + 1, height + 1))
            if node * 2 + 2 < len(tree) and tree[node * 2 + 2] != -1:
                queue.append((node * 2 + 2, height + 1)
        return max_height

if __name__ == '__main__':
    tree = list(map(int, input().split()))
    solution = Solution()
    print(solution.solve(tree))

