#include <iostream>
#include <queue>
#include <vector>

using namespace std;

class Solution {
public:
    void solve(vector<int>& tree){
        if (tree.empty()) return;
        queue<pair<int, int>> q;
        q.push({0, 0});
        int maxHeight = 0;
        while (!q.empty()){
            int node = q.front().first;
            int height = q.front().second;
            q.pop();
            maxHeight = max(maxHeight, height);
            if (node * 2 + 1 < tree.size() && tree[node * 2 + 1] != -1)
                q.push({node * 2 + 1, height + 1});
            if (node * 2 + 2 < tree.size() && tree[node * 2 + 2] != -1)
                q.push({node * 2 + 2, height + 1});
        }
        cout << maxHeight << endl;    }
};

int main(){
    int n;
    cin >> n;
    vector<int> tree(n);
    for (int i = 0; i < n; i++)
        cin >> tree[i];
    Solution().solve(tree);
    return 0;
}
